const now = new Date();
const prospects = $input.all().map(i => i.json);

// Sequence steps: initial, follow-up 1 (3 days), follow-up 2 (7 days), breakup (14 days)
const steps = [
  { step: 1, delay_days: 0, subject_tpl: 'Quick question about {company}', type: 'initial' },
  { step: 2, delay_days: 3, subject_tpl: 'Following up — {name}', type: 'followup1' },
  { step: 3, delay_days: 7, subject_tpl: 'One more thought for {company}', type: 'followup2' },
  { step: 4, delay_days: 14, subject_tpl: 'Should I close your file, {name}?', type: 'breakup' }
];

const toSend = [];

for (const p of prospects) {
  // Skip replied, bounced, or completed prospects
  if (p.replied === 'true' || p.replied === true) continue;
  if (p.bounced === 'true' || p.bounced === true) continue;
  if (p.status === 'completed' || p.status === 'unsubscribed') continue;

  const currentStep = parseInt(p.step || '0', 10);
  if (currentStep >= 4) continue; // All steps done

  const nextStepDef = steps[currentStep]; // 0-indexed: step 0 means send step 1
  if (!nextStepDef) continue;

  // Check if it's time to send
  const nextSendAt = p.next_send_at ? new Date(p.next_send_at) : new Date(0);
  if (now < nextSendAt) continue;

  const subject = nextStepDef.subject_tpl
    .replace('{name}', p.name || 'there')
    .replace('{company}', p.company || 'your team');

  toSend.push({
    email: p.email,
    name: p.name || 'there',
    company: p.company || '',
    title: p.title || '',
    campaign: p.campaign || 'default',
    step: nextStepDef.step,
    step_type: nextStepDef.type,
    subject,
    next_delay_days: steps[currentStep + 1] ? steps[currentStep + 1].delay_days : 0
  });
}

if (toSend.length === 0) {
  return [{ json: { skip: true, message: 'No emails due' } }];
}

return toSend.map(s => ({ json: s }));

const item = $input.first().json;
const templates = {
  initial: `<p>Hi ${item.name},</p><p>I came across ${item.company || 'your company'} and had a quick question about how you're currently handling automation.</p><p>We help businesses like yours save 10-20 hours per week with custom workflow automation. Would it be worth a quick chat?</p><p>Best regards</p>`,
  followup1: `<p>Hi ${item.name},</p><p>Just following up on my last email. I know you're busy, so I'll keep this brief.</p><p>We've helped similar companies reduce manual tasks by 60%+. Happy to share a quick case study if you're interested.</p><p>Best regards</p>`,
  followup2: `<p>Hi ${item.name},</p><p>One more thought — I noticed ${item.company || 'companies in your space'} often struggle with repetitive manual processes.</p><p>Would a 15-minute call be worth your time to explore if we can help?</p><p>Best regards</p>`,
  breakup: `<p>Hi ${item.name},</p><p>I've reached out a few times and haven't heard back, so I'll assume the timing isn't right.</p><p>I'll close your file for now, but feel free to reach out if things change. No hard feelings!</p><p>All the best</p>`
};

return [{
  json: {
    ...item,
    body: templates[item.step_type] || templates.initial
  }
}];
